// --- Application State ---
let dnaData = [...fallbackDnaData];
let fingermarkData = [...fallbackFingermarkData];
let globalGlossary = [];

let currentCategory = 'dna'; // 'dna' or 'fingermarks'
let globalContentMode = 'summary'; // 'summary' or 'extended'
let chapterModes = {}; // Map of chapter ID -> mode ('summary' or 'extended')
let bookmarks = []; // Array of {category, chapterNumber}
let globalSearchQuery = '';
let glossarySearchQuery = '';
let selectedGlossaryLetter = '';
let activeView = 'chapters'; // 'chapters' or 'glossary'

// --- Document Ready / Initialization ---
document.addEventListener('DOMContentLoaded', async () => {
    // 1. Try to load dynamic JSON files (override built-in if available)
    await loadDataFiles();
    
    // 2. Build glossary
    buildGlobalGlossary();
    
    // 3. Load bookmarks from localStorage
    loadBookmarks();
    
    // 4. Initialize chapterModes map
    initChapterModes();
    
    // 5. Render elements
    renderSidebarChapters();
    renderSidebarBookmarks();
    renderChapters();
    renderGlossaryLetters();
    renderGlossary();
    
    // 6. Handle URL Hash (if navigating directly to a section/glossary)
    handleUrlHash();
    window.addEventListener('hashchange', handleUrlHash);
});

// --- Data Loading ---
async function loadDataFiles() {
    try {
        const dnaRes = await fetch('data/dna_data.json');
        if (dnaRes.ok) {
            dnaData = await dnaRes.json();
            console.log("Successfully loaded DNA data from JSON file.");
        }
    } catch (e) {
        console.warn("Failed to fetch dna_data.json dynamically. Using built-in fallback.", e);
    }
    
    try {
        const fmRes = await fetch('data/fingermark_data.json');
        if (fmRes.ok) {
            fingermarkData = await fmRes.json();
            console.log("Successfully loaded Fingermarks data from JSON file.");
        }
    } catch (e) {
        console.warn("Failed to fetch fingermark_data.json dynamically. Using built-in fallback.", e);
    }
}

// --- Initialize Chapter View Modes ---
function initChapterModes() {
    // DNA Chapters (1 to 5)
    dnaData.forEach(ch => {
        chapterModes[`dna-${ch.chapter_number}`] = globalContentMode;
    });
    // Fingermark Chapters (1 to 5)
    fingermarkData.forEach(ch => {
        chapterModes[`fingermarks-${ch.chapter_number}`] = globalContentMode;
    });
}

// --- Build Global Glossary ---
function buildGlobalGlossary() {
    const termsMap = new Map();
    
    dnaData.forEach(ch => {
        if (ch.key_terms) {
            ch.key_terms.forEach(term => {
                const key = term.term_en.toLowerCase().trim();
                if (!termsMap.has(key)) {
                    termsMap.set(key, {
                        ...term,
                        category: 'dna',
                        chapter_number: ch.chapter_number,
                        chapter_title: ch.title_he
                    });
                }
            });
        }
    });

    fingermarkData.forEach(ch => {
        if (ch.key_terms) {
            ch.key_terms.forEach(term => {
                const key = term.term_en.toLowerCase().trim();
                if (!termsMap.has(key)) {
                    termsMap.set(key, {
                        ...term,
                        category: 'fingermarks',
                        chapter_number: ch.chapter_number,
                        chapter_title: ch.title_he
                    });
                }
            });
        }
    });

    globalGlossary = Array.from(termsMap.values()).sort((a, b) => 
        a.term_en.localeCompare(b.term_en)
    );
}

// --- Local Storage Bookmarks ---
function loadBookmarks() {
    const stored = localStorage.getItem('forensic_bookmarks');
    if (stored) {
        try {
            bookmarks = JSON.parse(stored);
        } catch (e) {
            bookmarks = [];
        }
    }
    updateBookmarkCount();
}

function saveBookmarks() {
    localStorage.setItem('forensic_bookmarks', JSON.stringify(bookmarks));
    updateBookmarkCount();
    renderSidebarBookmarks();
}

function updateBookmarkCount() {
    const countBadge = document.getElementById('bookmark-count');
    if (countBadge) {
        countBadge.textContent = bookmarks.length;
    }
}

function toggleBookmark(category, chapterNum) {
    const idx = bookmarks.findIndex(b => b.category === category && b.chapterNumber === chapterNum);
    const cardEl = document.getElementById(`chapter-card-${category}-${chapterNum}`);
    
    if (idx > -1) {
        // Remove bookmark
        bookmarks.splice(idx, 1);
        if (cardEl) cardEl.classList.remove('pinned');
    } else {
        // Add bookmark
        bookmarks.push({ category, chapterNumber: chapterNum });
        if (cardEl) cardEl.classList.add('pinned');
    }
    
    saveBookmarks();
    
    // Update the bookmark button icon state on the card itself
    const btn = document.querySelector(`#chapter-card-${category}-${chapterNum} .card-bookmark-btn`);
    if (btn) {
        if (idx > -1) {
            btn.classList.remove('active');
            btn.innerHTML = '<i class="fa-regular fa-star"></i>';
        } else {
            btn.classList.add('active');
            btn.innerHTML = '<i class="fa-solid fa-star"></i>';
        }
    }
}

function isBookmarked(category, chapterNum) {
    return bookmarks.some(b => b.category === category && b.chapterNumber === chapterNum);
}

// --- Switch Categories (DNA / Fingermarks) ---
function switchCategory(category) {
    currentCategory = category;
    activeView = 'chapters';
    
    // Update theme class on body
    const themeClass = category === 'fingermarks' ? 'theme-fm' : `theme-${category}`;
    document.body.className = `${themeClass} ${document.body.classList.contains('light-mode') ? 'light-mode' : 'dark-mode'}`;
    
    // Update Category switcher buttons
    document.getElementById('btn-cat-dna').classList.toggle('active', category === 'dna');
    document.getElementById('btn-cat-fm').classList.toggle('active', category === 'fingermarks');
    document.getElementById('btn-glossary-view').classList.remove('active');
    
    // Update logo icon dynamically based on category
    const logoIcon = document.getElementById('logo-icon-img');
    if (logoIcon) {
        if (category === 'dna') {
            logoIcon.className = 'fa-solid fa-dna logo-icon';
        } else if (category === 'fingermarks') {
            logoIcon.className = 'fa-solid fa-fingerprint logo-icon';
        }
    }
    
    // Toggle active sections in viewport
    document.getElementById('chapters-section').style.display = 'block';
    document.getElementById('glossary-section').style.display = 'none';
    
    // Update banner metadata
    const bannerTitle = document.getElementById('banner-title');
    const bannerDesc = document.getElementById('banner-description');
    const bannerIcon = document.getElementById('banner-icon-bg');
    
    if (category === 'dna') {
        bannerTitle.textContent = 'דנ"א וביולוגיה פורנזית';
        bannerDesc.textContent = 'סקירה מקיפה של התפתחויות מדעיות, שיטות הפקה, כלי תקינה וטכנולוגיות MPS/FIGG חדישות.';
        bannerIcon.className = 'fa-solid fa-dna banner-icon';
    } else {
        bannerTitle.textContent = 'טביעות אצבע וויזואליזציה';
        bannerDesc.textContent = 'מחקרים בהרכב הכימי של עקבות, שיטות הדמיה אופטיות, פיתוח ממיסים ירוקים והשפעת ריאגנטים על DNA.';
        bannerIcon.className = 'fa-solid fa-fingerprint banner-icon';
    }
    
    // Render the layout
    renderSidebarChapters();
    renderChapters();
    
    // Clear search status if any
    if (globalSearchQuery) {
        handleGlobalSearch();
    }
}

// --- Toggle Views (Chapters vs Glossary) ---
function toggleGlossaryView() {
    activeView = 'glossary';
    
    // Update theme class
    document.body.className = `theme-glossary ${document.body.classList.contains('light-mode') ? 'light-mode' : 'dark-mode'}`;
    
    // Toggle active buttons
    document.getElementById('btn-cat-dna').classList.remove('active');
    document.getElementById('btn-cat-fm').classList.remove('active');
    document.getElementById('btn-glossary-view').classList.add('active');
    
    // Toggle displays
    document.getElementById('chapters-section').style.display = 'none';
    document.getElementById('glossary-section').style.display = 'block';
    
    // Update logo icon to book in glossary view
    const logoIcon = document.getElementById('logo-icon-img');
    if (logoIcon) {
        logoIcon.className = 'fa-solid fa-book-open logo-icon';
    }
    
    renderGlossary();
}

function hideGlossaryView() {
    switchCategory(currentCategory);
}

// --- PDF Embedded Viewer & Split View ---
function openPdfViewer(pdfFile, pageNum, event) {
    if (event) event.preventDefault();
    
    const iframe = document.getElementById('pdf-iframe');
    const panel = document.getElementById('pdf-viewer-panel');
    const mainContent = document.querySelector('.main-content');
    
    if (iframe && panel && mainContent) {
        iframe.src = `pdf/${pdfFile}#page=${pageNum}`;
        const extLink = document.getElementById('pdf-external-link');
        if (extLink) extLink.href = `pdf/${pdfFile}#page=${pageNum}`;
        
        const titleSpan = document.getElementById('pdf-viewer-title');
        if (titleSpan) {
            titleSpan.textContent = `מסמך מקור - ${pdfFile === 'dna_report.pdf' ? 'ביולוגיה ודנ"א' : 'טביעות אצבע'} (עמוד ${pageNum})`;
        }
        
        panel.style.display = 'flex';
        mainContent.classList.add('split-active');
    }
}

function closePdfViewer() {
    const iframe = document.getElementById('pdf-iframe');
    const panel = document.getElementById('pdf-viewer-panel');
    const mainContent = document.querySelector('.main-content');
    
    if (mainContent) mainContent.classList.remove('split-active');
    if (panel) panel.style.display = 'none';
    if (iframe) iframe.src = '';
}

// --- Theme Toggle (Dark / Light Mode) ---
function toggleTheme() {
    const isLight = document.body.classList.contains('light-mode');
    const themeText = document.getElementById('theme-text');
    
    if (isLight) {
        document.body.classList.remove('light-mode');
        document.body.classList.add('dark-mode');
        if (themeText) themeText.textContent = 'מצב בהיר';
    } else {
        document.body.classList.remove('dark-mode');
        document.body.classList.add('light-mode');
        if (themeText) themeText.textContent = 'מצב כהה';
    }
}

// --- Global Content View Mode (Summary vs Extended) ---
function setGlobalMode(mode) {
    globalContentMode = mode;
    
    // Toggle buttons
    document.getElementById('btn-mode-summary').classList.toggle('active', mode === 'summary');
    document.getElementById('btn-mode-extended').classList.toggle('active', mode === 'extended');
    
    // Apply to all chapters of current category
    const activeData = currentCategory === 'dna' ? dnaData : fingermarkData;
    activeData.forEach(ch => {
        chapterModes[`${currentCategory}-${ch.chapter_number}`] = mode;
    });
    
    // Re-render
    renderChapters();
}

function toggleChapterMode(category, chapterNum, mode) {
    chapterModes[`${category}-${chapterNum}`] = mode;
    
    // Update local card UI
    const cardBody = document.querySelector(`#chapter-card-${category}-${chapterNum} .chapter-card-body`);
    const chapter = (category === 'dna' ? dnaData : fingermarkData).find(ch => ch.chapter_number === chapterNum);
    
    if (cardBody && chapter) {
        // Toggle active button
        const btnSummary = document.querySelector(`#chapter-card-${category}-${chapterNum} .btn-local-summary`);
        const btnExtended = document.querySelector(`#chapter-card-${category}-${chapterNum} .btn-local-extended`);
        
        if (btnSummary && btnExtended) {
            btnSummary.classList.toggle('active', mode === 'summary');
            btnExtended.classList.toggle('active', mode === 'extended');
        }
        
        // Update content body
        if (mode === 'summary') {
            cardBody.innerHTML = renderSummaryContent(chapter);
        } else {
            cardBody.innerHTML = renderExtendedContent(chapter);
        }
    }
}

// --- Utility: Format Texts (RTL/LTR formatting) ---
function formatHebrewText(text) {
    if (!text) return '';
    
    // 1. Replace markdown bold **text** with <strong>text</strong>
    const parsedText = text.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
    
    // 2. Wrap English letters/numbers/special characters (like technical codes) in a LTR tech-term span.
    // We split by HTML tags first to avoid wrapping inside existing HTML tags (like <strong> or <mark>).
    const englishRegex = /\b[A-Za-z0-9][A-Za-z0-9\s\/\-\.\(\)\,\:\&\+]*[A-Za-z0-9\)]\b|\b[A-Za-z0-9]\b/g;
    const parts = parsedText.split(/(<[^>]+>)/g);
    
    const formattedParts = parts.map(part => {
        if (part.startsWith('<')) {
            return part; // Skip HTML tags
        }
        return part.replace(englishRegex, (match) => {
            return `<span class="tech-term" dir="ltr">${match}</span>`;
        });
    });
    
    return formattedParts.join('');
}

function getPdfPage(sourcePages) {
    if (!sourcePages) return 1;
    const match = sourcePages.match(/\d+/);
    return match ? parseInt(match[0], 10) : 1;
}

// Tag-safe HTML text highlighter
function highlightText(html, query) {
    if (!query) return html;
    const escapedQuery = query.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
    
    // Split HTML by tags, only apply regex on text segments in between tags
    const parts = html.split(/(<[^>]+>)/g);
    const highlightedParts = parts.map(part => {
        if (part.startsWith('<') && part.endsWith('>')) {
            return part; // Return HTML tags as they are
        }
        const regex = new RegExp(`(${escapedQuery})`, 'gi');
        return part.replace(regex, '<span class="search-highlight">$1</span>');
    });
    return highlightedParts.join('');
}

// --- Rendering: Sidebar ---
function renderSidebarChapters() {
    const list = document.getElementById('sidebar-chapters');
    if (!list) return;
    
    list.innerHTML = '';
    const activeData = currentCategory === 'dna' ? dnaData : fingermarkData;
    
    activeData.forEach(ch => {
        const item = document.createElement('li');
        item.className = 'chapter-nav-item';
        item.setAttribute('id', `nav-item-${currentCategory}-${ch.chapter_number}`);
        item.onclick = () => {
            scrollToChapter(ch.chapter_number);
        };
        
        item.innerHTML = `
            <span class="chapter-nav-title">${ch.title_he.split(':')[1] || ch.title_he}</span>
            <span class="chapter-nav-num">פרק ${ch.chapter_number}</span>
        `;
        list.appendChild(item);
    });
    
    updateActiveSidebarChapter();
}

function renderSidebarBookmarks() {
    const list = document.getElementById('sidebar-bookmarks');
    if (!list) return;
    
    list.innerHTML = '';
    
    if (bookmarks.length === 0) {
        list.innerHTML = '<li class="empty-state-text">אין פרקים שמורים</li>';
        return;
    }
    
    bookmarks.forEach(b => {
        const dataSet = b.category === 'dna' ? dnaData : fingermarkData;
        const chapter = dataSet.find(ch => ch.chapter_number === b.chapterNumber);
        if (!chapter) return;
        
        const catLabel = b.category === 'dna' ? 'דנ"א' : 'טב"א';
        
        const item = document.createElement('li');
        item.className = 'bookmark-item';
        item.onclick = () => {
            if (currentCategory !== b.category) {
                switchCategory(b.category);
            }
            setTimeout(() => scrollToChapter(b.chapterNumber), 150);
        };
        
        item.innerHTML = `
            <div class="bookmark-item-title" title="${chapter.title_he}">
                <strong>[${catLabel}]</strong> ${chapter.title_he.split(':')[1] || chapter.title_he}
            </div>
            <button class="remove-bookmark-btn" onclick="event.stopPropagation(); toggleBookmark('${b.category}', ${b.chapterNumber})" title="הסר סימניה">
                <i class="fa-solid fa-trash-can"></i>
            </button>
        `;
        list.appendChild(item);
    });
}

function updateActiveSidebarChapter() {
    const items = document.querySelectorAll('.chapter-nav-item');
    items.forEach(el => el.classList.remove('active'));
    
    // Find which chapter is currently in view
    const activeData = currentCategory === 'dna' ? dnaData : fingermarkData;
    let inViewChapter = null;
    
    for (let i = 0; i < activeData.length; i++) {
        const ch = activeData[i];
        const el = document.getElementById(`chapter-card-${currentCategory}-${ch.chapter_number}`);
        if (el) {
            const rect = el.getBoundingClientRect();
            // If the element is near the top of the viewport
            if (rect.top <= 200 && rect.bottom >= 150) {
                inViewChapter = ch.chapter_number;
                break;
            }
        }
    }
    
    if (inViewChapter) {
        const navEl = document.getElementById(`nav-item-${currentCategory}-${inViewChapter}`);
        if (navEl) navEl.classList.add('active');
    }
}

// Listen to scroll events on main content to update sidebar active dot
window.addEventListener('scroll', updateActiveSidebarChapter);
document.querySelector('.main-content')?.addEventListener('scroll', updateActiveSidebarChapter);

function scrollToChapter(chapterNum) {
    const el = document.getElementById(`chapter-card-${currentCategory}-${chapterNum}`);
    if (el) {
        el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
}

// --- Rendering: Chapter Content helper ---
function renderSummaryContent(chapter) {
    const lines = chapter.summary_he.split('\n');
    let html = '<ul class="summary-bullets-list">';
    lines.forEach(line => {
        if (line.trim()) {
            // Clean up the bullet marker
            const cleanLine = line.replace(/^[\s•\-\*]+/, '').trim();
            // Highlight queries if search is active
            const formatted = formatHebrewText(cleanLine);
            const highlighted = globalSearchQuery ? highlightText(formatted, globalSearchQuery) : formatted;
            html += `<li>${highlighted}</li>`;
        }
    });
    html += '</ul>';
    return html;
}

function renderExtendedContent(chapter) {
    const paragraphs = chapter.extended_he.split('\n');
    let html = '<div class="extended-text-wrapper">';
    paragraphs.forEach(p => {
        if (p.trim()) {
            // Check if it looks like a list item (e.g. starting with "1. ")
            let pText = p.trim();
            const formatted = formatHebrewText(pText);
            const highlighted = globalSearchQuery ? highlightText(formatted, globalSearchQuery) : formatted;
            html += `<p>${highlighted}</p>`;
        }
    });
    html += '</div>';
    return html;
}

// --- Rendering: Chapters Grid ---
function renderChapters() {
    const container = document.getElementById('chapters-container');
    if (!container) return;
    
    container.innerHTML = '';
    const activeData = currentCategory === 'dna' ? dnaData : fingermarkData;
    
    // Filter by search query if applicable
    let filteredData = activeData;
    if (globalSearchQuery) {
        filteredData = activeData.filter(ch => {
            const query = globalSearchQuery.toLowerCase();
            const matchesTitle = ch.title_he.toLowerCase().includes(query) || ch.title_en.toLowerCase().includes(query);
            const matchesSummary = ch.summary_he.toLowerCase().includes(query);
            const matchesExtended = ch.extended_he.toLowerCase().includes(query);
            const matchesTerms = ch.key_terms && ch.key_terms.some(t => 
                t.term_en.toLowerCase().includes(query) || 
                t.term_he.toLowerCase().includes(query) || 
                t.definition_he.toLowerCase().includes(query)
            );
            return matchesTitle || matchesSummary || matchesExtended || matchesTerms;
        });
        
        // Show Search status bar
        const statusBar = document.getElementById('search-status');
        const statusText = document.getElementById('search-status-text');
        if (statusBar && statusText) {
            statusBar.style.display = 'flex';
            statusText.innerHTML = `נמצאו <strong>${filteredData.length}</strong> פרקים תואמים לחיפוש: "<strong>${globalSearchQuery}</strong>"`;
        }
    } else {
        const statusBar = document.getElementById('search-status');
        if (statusBar) statusBar.style.display = 'none';
    }
    
    if (filteredData.length === 0) {
        container.innerHTML = `
            <div class="glass-card" style="padding: 3rem; text-align: center; color: var(--text-muted);">
                <i class="fa-solid fa-circle-info" style="font-size: 2rem; margin-bottom: 1rem; color: var(--accent);"></i>
                <p>לא נמצאו פרקים העונים לחיפוש שלך.</p>
            </div>
        `;
        return;
    }
    
    filteredData.forEach(ch => {
        const cardId = `chapter-card-${currentCategory}-${ch.chapter_number}`;
        const mode = chapterModes[`${currentCategory}-${ch.chapter_number}`] || globalContentMode;
        
        // Highlighting Titles
        const rawTitleHe = ch.title_he;
        const rawTitleEn = ch.title_en;
        const highlightedTitleHe = globalSearchQuery ? highlightText(rawTitleHe, globalSearchQuery) : rawTitleHe;
        const highlightedTitleEn = globalSearchQuery ? highlightText(rawTitleEn, globalSearchQuery) : rawTitleEn;
        
        const card = document.createElement('article');
        card.className = `chapter-card glass-card ${isBookmarked(currentCategory, ch.chapter_number) ? 'pinned' : ''}`;
        card.setAttribute('id', cardId);
        
        card.innerHTML = `
            <!-- Chapter Pin Ribbon -->
            <div class="chapter-pin-indicator">
                <i class="fa-solid fa-thumbtack"></i>
            </div>
            
            <!-- Header -->
            <div class="chapter-card-header">
                <div class="chapter-card-meta">
                    <span class="chapter-badge-num">פרק ${ch.chapter_number}</span>
                    <h2 class="chapter-title-he">${highlightedTitleHe}</h2>
                    <div class="chapter-title-en" dir="ltr">${highlightedTitleEn}</div>
                </div>
                
                <div class="chapter-card-controls">
                    <!-- Chapter mode toggle -->
                    <div class="chapter-local-switch">
                        <button class="switch-option btn-local-summary ${mode === 'summary' ? 'active' : ''}" 
                                onclick="toggleChapterMode('${currentCategory}', ${ch.chapter_number}, 'summary')" title="תקציר">תקציר</button>
                        <button class="switch-option btn-local-extended ${mode === 'extended' ? 'active' : ''}" 
                                onclick="toggleChapterMode('${currentCategory}', ${ch.chapter_number}, 'extended')" title="הרחבה">הרחבה</button>
                    </div>
                    <!-- Bookmark -->
                    <button class="card-bookmark-btn ${isBookmarked(currentCategory, ch.chapter_number) ? 'active' : ''}" 
                            onclick="toggleBookmark('${currentCategory}', ${ch.chapter_number})" title="נעץ פרק">
                        <i class="${isBookmarked(currentCategory, ch.chapter_number) ? 'fa-solid' : 'fa-regular'} fa-star"></i>
                    </button>
                </div>
            </div>
            
            <!-- Content Body -->
            <div class="chapter-card-body">
                ${mode === 'summary' ? renderSummaryContent(ch) : renderExtendedContent(ch)}
            </div>
            
            <!-- Key Terms Badges -->
            ${ch.key_terms && ch.key_terms.length > 0 ? `
                <div class="chapter-key-terms">
                    <span class="key-terms-title"><i class="fa-solid fa-tags"></i> מונחי מפתח:</span>
                    ${ch.key_terms.map(t => {
                        const termLabel = globalSearchQuery ? highlightText(t.term_he, globalSearchQuery) : t.term_he;
                        return `
                            <span class="term-badge" onclick="navigateToGlossaryTerm('${t.term_en}')" title="${t.term_en} - ${t.definition_he}">
                                ${termLabel} <i class="fa-solid fa-chevron-left" style="font-size:0.6rem; opacity:0.6;"></i>
                            </span>
                        `;
                    }).join('')}
                </div>
            ` : ''}
            
            <!-- Media Players Section -->
            <div class="chapter-media-section">
                <div class="media-tabs">
                    <button class="media-tab-btn active" id="tab-audio-btn-${currentCategory}-${ch.chapter_number}" onclick="switchMediaTab('${currentCategory}', ${ch.chapter_number}, 'audio')">
                        <i class="fa-solid fa-headphones"></i> הסבר שמע
                    </button>
                    <button class="media-tab-btn" id="tab-video-btn-${currentCategory}-${ch.chapter_number}" onclick="switchMediaTab('${currentCategory}', ${ch.chapter_number}, 'video')">
                        <i class="fa-solid fa-circle-play"></i> סרטון הסבר
                    </button>
                </div>
                
                <div class="media-player-content">
                    <!-- Audio Panel -->
                    <div class="media-panel active" id="panel-audio-${currentCategory}-${ch.chapter_number}">
                        <div class="audio-player-wrapper" id="audio-wrapper-${currentCategory}-${ch.chapter_number}">
                            <!-- We will build custom controls below, and dynamic media loading -->
                        </div>
                    </div>
                    <!-- Video Panel -->
                    <div class="media-panel" id="panel-video-${currentCategory}-${ch.chapter_number}">
                        <div class="video-player-wrapper" id="video-wrapper-${currentCategory}-${ch.chapter_number}">
                            <!-- We will build custom video container -->
                        </div>
                    </div>
                </div>
            </div>
            
            <!-- Footer -->
            <div class="chapter-card-footer">
                <a href="pdf/${currentCategory === 'dna' ? 'dna_report.pdf' : 'fingermark_report.pdf'}#page=${getPdfPage(ch.source_pages)}" 
                   onclick="openPdfViewer('${currentCategory === 'dna' ? 'dna_report.pdf' : 'fingermark_report.pdf'}', ${getPdfPage(ch.source_pages)}, event)"
                   class="pdf-link-btn">
                    <i class="fa-solid fa-file-pdf"></i>
                    <span>דוח מקורי (עמוד ${getPdfPage(ch.source_pages)})</span>
                </a>
                
                <div class="card-source-page">
                    טווח עמודים בדוח: <span>${ch.source_pages}</span>
                </div>
            </div>
        `;
        
        container.appendChild(card);
        
        // Initialize Custom Media players for this card
        initMediaPlayers(currentCategory, ch);
    });
    
    // Trigger scroll position update
    updateActiveSidebarChapter();
}

// --- Media Tabs Switcher ---
function switchMediaTab(category, chapterNum, mediaType) {
    const tabAudio = document.getElementById(`tab-audio-btn-${category}-${chapterNum}`);
    const tabVideo = document.getElementById(`tab-video-btn-${category}-${chapterNum}`);
    const panelAudio = document.getElementById(`panel-audio-${category}-${chapterNum}`);
    const panelVideo = document.getElementById(`panel-video-${category}-${chapterNum}`);
    
    if (mediaType === 'audio') {
        tabAudio.classList.add('active');
        tabVideo.classList.remove('active');
        panelAudio.classList.add('active');
        panelVideo.classList.remove('active');
        
        // Pause video if playing
        const videoEl = document.querySelector(`#video-wrapper-${category}-${chapterNum} video`);
        if (videoEl) videoEl.pause();
    } else {
        tabAudio.classList.remove('active');
        tabVideo.classList.add('active');
        panelAudio.classList.remove('active');
        panelVideo.classList.add('active');
        
        // Pause audio if playing
        const audioEl = document.querySelector(`#audio-wrapper-${category}-${chapterNum} audio`);
        if (audioEl) audioEl.pause();
    }
}

// --- Initialize Audio/Video Element & Custom Players ---
function initMediaPlayers(category, chapter) {
    const audioWrapper = document.getElementById(`audio-wrapper-${category}-${chapter.chapter_number}`);
    const videoWrapper = document.getElementById(`video-wrapper-${category}-${chapter.chapter_number}`);
    
    if (!audioWrapper || !videoWrapper) return;
    
    const audioUrl = chapter.audio_path;
    const videoUrl = chapter.video_path;
    
    // 1. Build Audio Player
    const audioEl = document.createElement('audio');
    audioEl.preload = 'none';
    audioEl.src = audioUrl;
    audioWrapper.appendChild(audioEl);
    
    // Add custom audio player UI
    const customAudioUI = document.createElement('div');
    customAudioUI.className = 'custom-audio-player';
    customAudioUI.innerHTML = `
        <div class="player-row-main">
            <button class="play-pause-btn btn-play" onclick="togglePlayAudio('${category}', ${chapter.chapter_number})">
                <i class="fa-solid fa-play"></i>
            </button>
            
            <div class="timeline-container">
                <input type="range" class="time-slider" value="0" min="0" max="100">
                <div class="time-labels">
                    <span class="time-current">0:00</span>
                    <span class="time-duration">0:00</span>
                </div>
            </div>
            
            <div class="volume-speed-controls">
                <div class="volume-wrap">
                    <button class="volume-btn" onclick="toggleMuteAudio('${category}', ${chapter.chapter_number})">
                        <i class="fa-solid fa-volume-high"></i>
                    </button>
                    <input type="range" class="volume-slider" min="0" max="1" step="0.1" value="0.8">
                </div>
                <select class="speed-select" onchange="setAudioSpeed(this, '${category}', ${chapter.chapter_number})">
                    <option value="1">1.0x</option>
                    <option value="1.25">1.25x</option>
                    <option value="1.5">1.5x</option>
                    <option value="2">2.0x</option>
                </select>
            </div>
        </div>
    `;
    audioWrapper.appendChild(customAudioUI);
    
    // Audio Player Event Listeners
    const playBtn = customAudioUI.querySelector('.play-pause-btn');
    const timeSlider = customAudioUI.querySelector('.time-slider');
    const timeCurrent = customAudioUI.querySelector('.time-current');
    const timeDuration = customAudioUI.querySelector('.time-duration');
    const volumeBtn = customAudioUI.querySelector('.volume-btn');
    const volumeSlider = customAudioUI.querySelector('.volume-slider');
    
    audioEl.addEventListener('loadedmetadata', () => {
        timeSlider.max = Math.floor(audioEl.duration);
        timeDuration.textContent = formatTime(audioEl.duration);
    });
    
    audioEl.addEventListener('timeupdate', () => {
        if (!timeSlider.seeking) {
            timeSlider.value = Math.floor(audioEl.currentTime);
            timeCurrent.textContent = formatTime(audioEl.currentTime);
        }
    });
    
    timeSlider.addEventListener('input', () => {
        timeSlider.seeking = true;
        timeCurrent.textContent = formatTime(timeSlider.value);
    });
    
    timeSlider.addEventListener('change', () => {
        audioEl.currentTime = timeSlider.value;
        timeSlider.seeking = false;
    });
    
    volumeSlider.addEventListener('input', () => {
        audioEl.volume = volumeSlider.value;
        audioEl.muted = (audioEl.volume === 0);
        updateVolumeIcon(volumeBtn, audioEl.volume, audioEl.muted);
    });
    
    // HANDLE AUDIO ERROR GRACEFULLY
    audioEl.addEventListener('error', () => {
        showMediaPlaceholder(audioWrapper, 'audio', audioUrl);
    });
    
    
    // 2. Build Video Player
    const videoContainer = document.createElement('div');
    videoContainer.className = 'custom-video-player-wrapper';
    
    const videoEl = document.createElement('video');
    videoEl.controls = true;
    videoEl.preload = 'none';
    videoEl.src = videoUrl;
    
    videoContainer.appendChild(videoEl);
    videoWrapper.appendChild(videoContainer);
    
    // HANDLE VIDEO ERROR GRACEFULLY
    videoEl.addEventListener('error', () => {
        showMediaPlaceholder(videoWrapper, 'video', videoUrl);
    });
}

function showMediaPlaceholder(wrapper, type, fileUrl) {
    wrapper.innerHTML = `
        <div class="media-placeholder glass-card">
            <i class="fa-solid fa-triangle-exclamation placeholder-icon"></i>
            <h4 class="placeholder-title">סקירת ${type === 'audio' ? 'שמע' : 'וידאו'} בעברית בקרוב</h4>
            <p class="placeholder-subtitle">[File: ${fileUrl}]</p>
        </div>
    `;
}

// Media Player Helpers
function formatTime(secs) {
    const minutes = Math.floor(secs / 60);
    const seconds = Math.floor(secs % 60);
    return `${minutes}:${seconds < 10 ? '0' : ''}${seconds}`;
}

function updateVolumeIcon(btnEl, vol, muted) {
    const icon = btnEl.querySelector('i');
    if (muted || vol === 0) {
        icon.className = 'fa-solid fa-volume-xmark';
    } else if (vol < 0.5) {
        icon.className = 'fa-solid fa-volume-low';
    } else {
        icon.className = 'fa-solid fa-volume-high';
    }
}

// Custom Player Global Handlers
function togglePlayAudio(category, chapterNum) {
    const audio = document.querySelector(`#audio-wrapper-${category}-${chapterNum} audio`);
    const btn = document.querySelector(`#audio-wrapper-${category}-${chapterNum} .play-pause-btn`);
    if (!audio || !btn) return;
    
    if (audio.paused) {
        audio.play().catch(err => {
            // If play fails (e.g. file not found, which triggers error event), it's handled.
            console.log("Audio play attempt failed, error listener will trigger placeholder.", err);
        });
        btn.innerHTML = '<i class="fa-solid fa-pause"></i>';
    } else {
        audio.pause();
        btn.innerHTML = '<i class="fa-solid fa-play"></i>';
    }
}

function toggleMuteAudio(category, chapterNum) {
    const audio = document.querySelector(`#audio-wrapper-${category}-${chapterNum} audio`);
    const btn = document.querySelector(`#audio-wrapper-${category}-${chapterNum} .volume-btn`);
    const slider = document.querySelector(`#audio-wrapper-${category}-${chapterNum} .volume-slider`);
    if (!audio || !btn || !slider) return;
    
    audio.muted = !audio.muted;
    slider.value = audio.muted ? 0 : audio.volume;
    updateVolumeIcon(btn, audio.volume, audio.muted);
}

function setAudioSpeed(selectEl, category, chapterNum) {
    const audio = document.querySelector(`#audio-wrapper-${category}-${chapterNum} audio`);
    if (audio) {
        audio.playbackRate = parseFloat(selectEl.value);
    }
}


// --- Rendering: Glossary (Milon) ---
function renderGlossaryLetters() {
    const container = document.getElementById('glossary-letters');
    if (!container) return;
    
    container.innerHTML = '';
    
    // Add "All" filter button
    const btnAll = document.createElement('button');
    btnAll.className = `letter-btn ${(!selectedGlossaryLetter) ? 'active' : ''}`;
    btnAll.textContent = 'הכל';
    btnAll.onclick = () => filterGlossaryByLetter('');
    container.appendChild(btnAll);
    
    // Get unique starting letters in English
    const enLetters = new Set();
    globalGlossary.forEach(t => {
        const first = t.term_en.charAt(0).toUpperCase();
        if (/[A-Z]/.test(first)) enLetters.add(first);
    });
    const sortedEn = Array.from(enLetters).sort();
    
    sortedEn.forEach(letter => {
        const btn = document.createElement('button');
        btn.className = `letter-btn ${selectedGlossaryLetter === letter ? 'active' : ''}`;
        btn.textContent = letter;
        btn.onclick = () => filterGlossaryByLetter(letter);
        container.appendChild(btn);
    });
    
    // Add separator
    const separator = document.createElement('span');
    separator.style.borderLeft = '1px solid var(--border-color)';
    separator.style.margin = '0 6px';
    container.appendChild(separator);
    
    // Get unique starting letters in Hebrew
    const heLetters = new Set();
    globalGlossary.forEach(t => {
        const first = t.term_he.charAt(0);
        if (/[\u0590-\u05FF]/.test(first)) heLetters.add(first);
    });
    const sortedHe = Array.from(heLetters).sort((a,b) => a.localeCompare(b, 'he'));
    
    sortedHe.forEach(letter => {
        const btn = document.createElement('button');
        btn.className = `letter-btn hebrew ${selectedGlossaryLetter === letter ? 'active' : ''}`;
        btn.textContent = letter;
        btn.onclick = () => filterGlossaryByLetter(letter);
        container.appendChild(btn);
    });
}

function filterGlossaryByLetter(letter) {
    selectedGlossaryLetter = letter;
    renderGlossaryLetters();
    renderGlossary();
}

function renderGlossary() {
    const container = document.getElementById('glossary-container');
    if (!container) return;
    
    container.innerHTML = '';
    
    let filtered = globalGlossary;
    
    // Apply Letter Filter
    if (selectedGlossaryLetter) {
        filtered = filtered.filter(t => {
            const firstEn = t.term_en.charAt(0).toUpperCase();
            const firstHe = t.term_he.charAt(0);
            return firstEn === selectedGlossaryLetter || firstHe === selectedGlossaryLetter;
        });
    }
    
    // Apply Glossary Search Query Filter
    if (glossarySearchQuery) {
        const query = glossarySearchQuery.toLowerCase();
        filtered = filtered.filter(t => 
            t.term_en.toLowerCase().includes(query) || 
            t.term_he.toLowerCase().includes(query) || 
            t.definition_he.toLowerCase().includes(query)
        );
    }
    
    if (filtered.length === 0) {
        container.innerHTML = `
            <div class="no-glossary-results">
                <i class="fa-solid fa-magnifying-glass-minus" style="font-size: 2rem; margin-bottom: 0.5rem;"></i>
                <p>לא נמצאו מונחים תואמים לחיפוש/סינון.</p>
            </div>
        `;
        return;
    }
    
    filtered.forEach(t => {
        const card = document.createElement('div');
        card.className = 'glossary-card glass-card';
        card.setAttribute('id', `glossary-term-${encodeURIComponent(t.term_en)}`);
        
        const catLabel = t.category === 'dna' ? 'דנ"א וביולוגיה' : 'טביעות אצבע';
        
        // Highlight logic
        const highlightedEn = glossarySearchQuery ? highlightText(t.term_en, glossarySearchQuery) : t.term_en;
        const highlightedHe = glossarySearchQuery ? highlightText(t.term_he, glossarySearchQuery) : t.term_he;
        const highlightedDef = glossarySearchQuery ? highlightText(t.definition_he, glossarySearchQuery) : t.definition_he;
        
        card.innerHTML = `
            <div class="glossary-card-header">
                <div class="glossary-term-en" dir="ltr">${highlightedEn}</div>
                <span class="glossary-source-tag" onclick="navigateToChapter('${t.category}', ${t.chapter_number})" title="עבור אל ${catLabel}, פרק ${t.chapter_number}">
                    ${catLabel}, פרק ${t.chapter_number}
                </span>
            </div>
            <div class="glossary-term-he">${highlightedHe}</div>
            <p class="glossary-definition">${highlightedDef}</p>
        `;
        container.appendChild(card);
    });
}

// --- Navigation from Glossary back to Chapter ---
function navigateToChapter(category, chapterNum) {
    if (currentCategory !== category) {
        switchCategory(category);
    }
    // Switch to chapters view if we were in glossary
    document.getElementById('chapters-section').style.display = 'block';
    document.getElementById('glossary-section').style.display = 'none';
    document.getElementById('btn-glossary-view').classList.remove('active');
    
    activeView = 'chapters';
    
    setTimeout(() => {
        const el = document.getElementById(`chapter-card-${category}-${chapterNum}`);
        if (el) {
            el.scrollIntoView({ behavior: 'smooth', block: 'start' });
            // Flash color animation
            el.style.boxShadow = `0 0 20px var(--accent)`;
            setTimeout(() => {
                el.style.boxShadow = '';
            }, 1500);
        }
    }, 150);
}

// --- Navigation from Chapter Tag to Glossary ---
function navigateToGlossaryTerm(termEn) {
    toggleGlossaryView();
    selectedGlossaryLetter = '';
    glossarySearchQuery = termEn;
    
    // Fill the glossary input search
    const input = document.getElementById('glossary-search-input');
    if (input) input.value = termEn;
    
    renderGlossaryLetters();
    renderGlossary();
    
    // Scroll to the card
    setTimeout(() => {
        const el = document.getElementById(`glossary-term-${encodeURIComponent(termEn)}`);
        if (el) {
            el.scrollIntoView({ behavior: 'smooth', block: 'center' });
            el.style.boxShadow = `0 0 20px var(--accent)`;
            setTimeout(() => {
                el.style.boxShadow = '';
            }, 1500);
        }
    }, 150);
}

// --- Global Search handler ---
function handleGlobalSearch() {
    const input = document.getElementById('global-search');
    const clearBtn = document.getElementById('clear-search');
    if (!input) return;
    
    globalSearchQuery = input.value.trim();
    
    if (clearBtn) {
        clearBtn.style.display = globalSearchQuery ? 'block' : 'none';
    }
    
    if (activeView === 'glossary') {
        glossarySearchQuery = globalSearchQuery;
        const glossaryInput = document.getElementById('glossary-search-input');
        if (glossaryInput) glossaryInput.value = globalSearchQuery;
        renderGlossary();
    } else {
        renderChapters();
    }
}

function clearGlobalSearch() {
    const input = document.getElementById('global-search');
    const clearBtn = document.getElementById('clear-search');
    if (input) input.value = '';
    if (clearBtn) clearBtn.style.display = 'none';
    
    globalSearchQuery = '';
    
    if (activeView === 'glossary') {
        glossarySearchQuery = '';
        const glossaryInput = document.getElementById('glossary-search-input');
        if (glossaryInput) glossaryInput.value = '';
        renderGlossary();
    } else {
        renderChapters();
    }
}

// --- Glossary Search input handler ---
function handleGlossarySearch() {
    const input = document.getElementById('glossary-search-input');
    if (input) {
        glossarySearchQuery = input.value.trim();
        renderGlossary();
    }
}

// --- Hash-based Routing (Deep Links) ---
function handleUrlHash() {
    const hash = window.location.hash;
    if (!hash) return;
    
    if (hash === '#glossary') {
        toggleGlossaryView();
    } else if (hash.startsWith('#chapter-')) {
        const parts = hash.split('-');
        if (parts.length === 3) {
            const category = parts[1]; // 'dna' or 'fingermarks'
            const chNum = parseInt(parts[2], 10);
            navigateToChapter(category, chNum);
        }
    }
}
